import re
import json
import ast
from typing import Any, Optional, Tuple


def solve(packet: str) -> int:
    def checksum(version: int, payload: str) -> int:
        return (version + sum(ord(c) for c in payload)) % 256

    def parse_int(value: Any) -> Optional[int]:
        if isinstance(value, bool):
            return int(value)
        if isinstance(value, int):
            return value
        if isinstance(value, str):
            s = value.strip()
            if not s:
                return None
            try:
                return int(s, 0)
            except ValueError:
                return None
        return None

    def from_mapping(obj: dict) -> Optional[Tuple[int, str]]:
        lower = {str(k).lower(): v for k, v in obj.items()}
        v = None
        p = None

        for key in ("version", "ver", "v"):
            if key in lower:
                v = parse_int(lower[key])
                break

        for key in ("payload", "data", "body", "p"):
            if key in lower:
                p = str(lower[key])
                break

        if v is not None and p is not None:
            return v, p
        return None

    s = packet.strip()

    for loader in (json.loads, ast.literal_eval):
        try:
            obj = loader(s)
            if isinstance(obj, dict):
                parsed = from_mapping(obj)
                if parsed is not None:
                    return checksum(*parsed)
            elif isinstance(obj, (list, tuple)) and len(obj) >= 2:
                v = parse_int(obj[0])
                if v is not None:
                    return checksum(v, str(obj[1]))
        except Exception:
            pass

    m = re.search(
        r"(?i)\b(?:version|ver|v)\b\s*[:=]\s*([+-]?(?:0x[0-9a-f]+|\d+))"
        r".*?\b(?:payload|data|body|p)\b\s*[:=]\s*(['\"]?)(.*?)\2"
        r"(?:\s*(?:[,;|]\s*(?:checksum|check|cs|c)\b\s*[:=]|$))",
        s,
        re.DOTALL,
    )
    if m:
        return checksum(int(m.group(1), 0), m.group(3))

    m = re.search(
        r"(?i)\b(?:payload|data|body|p)\b\s*[:=]\s*(['\"]?)(.*?)\1"
        r".*?\b(?:version|ver|v)\b\s*[:=]\s*([+-]?(?:0x[0-9a-f]+|\d+))",
        s,
        re.DOTALL,
    )
    if m:
        return checksum(int(m.group(3), 0), m.group(2))

    m = re.fullmatch(r"\s*[vV]?([+-]?(?:0x[0-9a-fA-F]+|\d+))\s*[:|,;]\s*(.*?)\s*", s, re.DOTALL)
    if m:
        return checksum(int(m.group(1), 0), m.group(2))

    m = re.fullmatch(r"\s*(.*?)\s*[:|,;]\s*[vV]?([+-]?(?:0x[0-9a-fA-F]+|\d+))\s*", s, re.DOTALL)
    if m:
        return checksum(int(m.group(2), 0), m.group(1))

    m = re.match(r"\s*[vV]([+-]?\d+)(.*)\Z", s, re.DOTALL)
    if m:
        payload = m.group(2)
        if payload.startswith(("-", "_", ":", "|", ";", ",")):
            payload = payload[1:]
        return checksum(int(m.group(1)), payload)

    m = re.match(r"\s*([+-]?\d+)(.*)\Z", s, re.DOTALL)
    if m:
        payload = m.group(2)
        if payload.startswith(("-", "_", ":", "|", ";", ",")):
            payload = payload[1:]
        return checksum(int(m.group(1)), payload)

    return checksum(0, packet)

