    bits = "".join(f"{int(ch, 16):04b}" for ch in packet)

    def parse(pos: int) -> tuple[int, int]:
        version_sum = int(bits[pos:pos + 3], 2)
        type_id = int(bits[pos + 3:pos + 6], 2)
        pos += 6

        if type_id == 4:
            while True:
                prefix = bits[pos]
                pos += 5
                if prefix == "0":
                    break
        else:
            length_type_id = bits[pos]
            pos += 1

            if length_type_id == "0":
