                    pos, child_sum = parse(pos)
                    version_sum += child_sum
            else:
                packet_count = int(bits[pos:pos + 11], 2)
                pos += 11
                for _ in range(packet_count):
                    pos, child_sum = parse(pos)
                    version_sum += child_sum

        return pos, version_sum

    _, checksum = parse(0)
    return checksum

