from typing import Any, Optional


def solve(packet: str) -> float:
    def bad() -> float:
        return -1.0

    def is_num(x: Any) -> bool:
        return isinstance(x, (int, float)) and not isinstance(x, bool) and math.isfinite(float(x))

    def nums_from_text(s: str) -> list[float]:
        return [float(x) for x in re.findall(r"[-+]?(?:\d+(?:\.\d*)?|\.\d+)", s)]

    def get_key(d: dict, names: set[str]) -> Any:
        lowered = {str(k).lower(): k for k in d.keys()}
        for name in names:
            if name in lowered:
                return d[lowered[name]]
        return None

    def parse_token_value(v: Any) -> list[float]:
        if v is None:
            return []
        if is_num(v):
            return [float(v)]
        if isinstance(v, (list, tuple)):
            out = []
            for item in v:
                if is_num(item):
                    out.append(float(item))
                elif isinstance(item, str):
                    out.extend(nums_from_text(item))
                else:
                    return []
            return out
        if isinstance(v, str):
            return nums_from_text(v)
        return []

    def checksum_ok(chk: float, channel: float, tokens: list[float]) -> bool:
