import json
import ast
import re

def solve(packet1: str, packet2: str) -> int:
    def to_int_like(x):
        if isinstance(x, bool):
            return int(x)
        if isinstance(x, int):
            return x
        if isinstance(x, float):
            return int(x)
        if x is None:
            return 0
        if isinstance(x, str):
            s = x.strip()
            if re.fullmatch(r"[+-]?\d+", s):
                return int(s)
            return sum(ord(c) for c in s)
        if isinstance(x, dict):
            return checksum_map(parse_obj(x)[0])
        if isinstance(x, (list, tuple)):
            return sum((i + 1) * to_int_like(v) for i, v in enumerate(x))
        return sum(ord(c) for c in str(x))

    def parse_scalar(s):
        s = str(s).strip()
        if re.fullmatch(r"[+-]?\d+", s):
            return int(s)
        if re.fullmatch(r"[+-]?(?:\d+\.\d*|\d*\.\d+)", s):
            return int(float(s))
        return s

    def parse_obj(obj):
        records = {}
        is_mapping = True

        if isinstance(obj, dict):
            if "records" in obj and isinstance(obj["records"], (list, tuple, dict)):
                return parse_obj(obj["records"])
            for k, v in obj.items():
                if str(k).lower() in {"checksum", "check", "crc"}:
                    continue
                if isinstance(v, dict) and any(x in v for x in ("value", "val", "data", "amount", "payload")):
                    for vf in ("value", "val", "data", "amount", "payload"):
                        if vf in v:
                            v = v[vf]
                            break
                records[parse_scalar(k)] = v
            return records, is_mapping

        if isinstance(obj, (list, tuple)):
            for idx, item in enumerate(obj):
                if isinstance(item, dict):
                    key = None
                    val = None
                    for kf in ("id", "key", "name", "record", "record_id"):
                        if kf in item:
                            key = item[kf]
                            break
                    for vf in ("value", "val", "data", "amount", "payload"):
                        if vf in item:
                            val = item[vf]
                            break
                    if key is None:
                        key = idx
                    if val is None:
                        val = {k: v for k, v in item.items() if k not in {"id", "key", "name", "record", "record_id"}}
                    records[parse_scalar(key)] = val
                elif isinstance(item, (list, tuple)) and len(item) >= 2:
                    records[parse_scalar(item[0])] = item[1]
                else:
                    records[idx] = item
            return records, is_mapping

        return {0: obj}, False

    def parse_packet(packet):
        text = "" if packet is None else str(packet).strip()
        if not text:
            return {}

        for loader in (json.loads, ast.literal_eval):
            try:
                obj = loader(text)
                recs, _ = parse_obj(obj)
                return recs
            except Exception:
                pass

        records = {}
        parts = [p.strip() for p in re.split(r"[;\n|,]+", text) if p.strip()]
        pair_found = False

        for part in parts:
            m = re.match(r"^\s*([^:=\s]+)\s*[:=]\s*(.*?)\s*$", part)
            if m:
                records[parse_scalar(m.group(1))] = parse_scalar(m.group(2))
                pair_found = True
            else:
                nums = re.findall(r"[+-]?\d+", part)
                if len(nums) >= 2:
