            re.compile(r'(<\s*channel\s*>)(.*?)(<\s*/\s*channel\s*>)', re.IGNORECASE | re.DOTALL),
            lambda m: m.group(1) + new_channel + m.group(3),
        ),
        (
            re.compile(r'([?&;]channel=)([^&#;\s]*)', re.IGNORECASE),
            lambda m: m.group(1) + new_channel,
        ),
        (
            re.compile(r'(^[ \t]*channel[ \t]*:[ \t]*)(.*?)(\r?$)', re.IGNORECASE | re.MULTILINE),
            lambda m: m.group(1) + new_channel + m.group(3),
        ),
        (
            re.compile(r'((?:["\']channel["\']|\bchannel\b)\s*[:=]\s*)([^,;&\s}\]\r\n]+)', re.IGNORECASE),
            lambda m: m.group(1) + new_channel,
        ),
    ]

    for pattern, repl in patterns:
        result, count = pattern.subn(repl, packet, count=1)
        if count:
            return result

    line_ending = ""
    core = packet
    if core.endswith("\r\n"):
        core, line_ending = core[:-2], "\r\n"
    elif core.endswith("\n"):
        core, line_ending = core[:-1], "\n"

    m = re.match(r'(:\S+\s+)?(\S+)(\s+)(.*)', core, re.DOTALL)
    if m:
        prefix, command, sep, rest = m.group(1) or "", m.group(2), m.group(3), m.group(4)
        cmd = command.upper()
        if cmd in {"PRIVMSG", "NOTICE", "JOIN", "PART", "TOPIC", "MODE", "KICK", "INVITE"}:
            if rest:
                first, *remaining = rest.split(" ", 1)
                rest = new_channel + ((" " + remaining[0]) if remaining else "")
                return prefix + command + sep + rest + line_ending

    result, count = re.subn(r'#[^\s,;:]+', new_channel, packet, count=1)
    if count:
        return result

    for delimiter in ("|", ",", ";", "\t", ":"):
        if delimiter in packet:
            before, after = packet.split(delimiter, 1)
            leading = before[:len(before) - len(before.lstrip())]
            trailing = before[len(before.rstrip()):]
            return leading + new_channel + trailing + delimiter + after

    parts = packet.split(maxsplit=1)
    if len(parts) == 2:
        return new_channel + packet[len(parts[0]):]
    if packet:
        return new_channel

    return original
